final:
module RefModule(CLK, LOAD, DATA_IN, SHIFT_IN, Q);
input CLK, LOAD;
input [3:0] DATA_IN;
input SHIFT_IN;
output [3:0] Q;
reg [3:0] Q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge CLK or posedge dbg_halt) begin
    if (LOAD)
        Q <= DATA_IN;
    else
        Q <= {SHIFT_IN, Q[3:1]};
end

endmodule
